      ...task,
      approvedContentTemplate: task.approvedContentTemplate || src.tpl,
      contentTaskTemplate: task.contentTaskTemplate || src.tpl,
      linkedContentTemplateStatus: 'approved',
      contentTemplateApproved: true,
