/* MZJ v423 - Safe UI only: show selected creative details as 4 cards without touching save logic */
(function(){
  try{ window.MZJ_APP_VERSION = '424'; }catch(_){ }
  const clean = value => (typeof normalizeText === 'function' ? normalizeText(value || '') : String(value || '').trim());
  const esc = value => (typeof escapeHtml === 'function' ? escapeHtml(value) : String(value || '').replace(/[&<>"']/g, ch => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[ch])));
  const makeId = () => (typeof instanceId === 'function' ? instanceId() : `creative-${Date.now()}-${Math.random().toString(36).slice(2,7)}`);
  function roleLabel(role){
    if(typeof defaultRoleSectionName === 'function') return defaultRoleSectionName(role);
    return ({ shooting:'قسم التصوير', design:'قسم التصميم', montage:'قسم المونتاج' })[role] || role;
  }
  function orderedRolesForCreative(name){
    const mainRole = typeof creativeDepartmentRole === 'function' ? creativeDepartmentRole(name) : 'montage';
    const roles = ['shooting','design','montage'];
    return [mainRole, ...roles.filter(role => role !== mainRole)];
  }
  function roleCardHtml(role, mainRole){
    const hint = role === mainRole ? 'القسم الأساسي المرتبط بالكريتيف' : 'قسم إضافي مرتبط بالمسار التنفيذي';
    const block = typeof roleAssignmentBlock === 'function' ? roleAssignmentBlock(role, roleLabel(role), hint) : '';
    return `<section class="v423-creative-card v423-role-card${role === mainRole ? ' is-main-role' : ''}" data-v423-role-card="${esc(role)}">
      <div class="v423-card-head"><span>${esc(role === mainRole ? 'القسم الأساسي' : 'قسم تنفيذي')}</span><strong>${esc(roleLabel(role))}</strong></div>
      ${block}
    </section>`;
  }
  function carListHtml(){
    return typeof creativeCarCheckboxList === 'function' ? creativeCarCheckboxList() : '';
  }
  creativeAssignmentPanelHtml = function(creativeName){
    const name = clean(creativeName);
    const key = typeof creativeSafeKey === 'function' ? creativeSafeKey(name) : name.replace(/\W+/g, '-');
    const mainRole = typeof creativeDepartmentRole === 'function' ? creativeDepartmentRole(name) : 'montage';
    const roles = orderedRolesForCreative(name);
    const roleCards = roles.map(role => roleCardHtml(role, mainRole)).join('');
    return `<article class="creative-assignment-panel creative-assignment-panel-v93 v423-creative-cards-panel is-active" data-creative-name="${esc(name)}" data-creative-key="${esc(key)}" data-creative-main-role="${esc(mainRole)}" data-creative-instance-id="${esc(makeId())}">
      <input class="js-creative-quantity" type="hidden" value="1" />
      <div class="v423-selected-creative-head">
        <div><span>الكريتيف المختار</span><strong>${esc(name)}</strong><small>رتبنا الاختيارات في 4 كروت واضحة بدون تغيير منطق الحفظ.</small></div>
      </div>
      <div class="v423-creative-work-grid">
        <section class="v423-creative-card v423-car-card v93-car-column">
          <div class="v423-card-head"><span>اختياري</span><strong>اختيار السيارة</strong></div>
          <label class="creative-car-needed-field"><span>اختيار سيارة؟</span><select class="js-creative-car-needed"><option value="">اختر نعم أو لا</option><option value="yes">نعم</option><option value="no">لا</option></select></label>
          <label class="creative-car-count-field is-hidden"><span>كام سيارة؟</span><input class="js-creative-car-count" type="number" min="1" max="50" inputmode="numeric" placeholder="اكتب عدد السيارات" /></label>
          <div class="creative-stock-picker-hint">اختار نعم ثم اكتب عدد السيارات عشان يظهر اختيار سيارات الاستوك.</div>
          <div class="creative-stock-picker-block is-hidden">
            <input class="v93-car-search" type="search" placeholder="بحث في السيارات..." aria-label="بحث في السيارات" />
            <div class="car-checkbox-grid creative-car-checkbox-grid">${carListHtml()}</div>
          </div>
          <label class="creative-panel-note-field"><span>ملاحظة للكريتيف</span><textarea class="js-creative-panel-note" rows="3" placeholder="ملاحظة خاصة بهذا الكريتيف... أو اتركها فارغة"></textarea></label>
          <button class="btn btn-primary js-v93-save-current-creative" type="button">حفظ الكريتيف الحالي</button>
        </section>
        ${roleCards}
      </div>
    </article>`;
  };
  function markStudio(modal){
    if(!modal) return;
    modal.classList.add('v423-dynamic-cards-ui');
    const help = modal.querySelector('.v93-popup-head p');
    if(help) help.textContent = 'اختار كريتيف، هتظهر تحته 4 كروت: السيارة ثم الأقسام التنفيذية بترتيب ديناميكي حسب نوع الكريتيف.';
  }
  const oldOpen = typeof openCreativeAssignmentPopup === 'function' ? openCreativeAssignmentPopup : null;
  if(oldOpen){
    openCreativeAssignmentPopup = function(){
      const result = oldOpen.apply(this, arguments);
      setTimeout(() => markStudio(document.getElementById('creativeAssignmentPopup')), 60);
      setTimeout(() => markStudio(document.getElementById('creativeAssignmentPopup')), 300);
      return result;
    };
  }
  document.addEventListener('click', function(event){
    if(event.target.closest('#creativeAssignmentPopup .v93-creative-pick')){
      setTimeout(() => markStudio(document.getElementById('creativeAssignmentPopup')), 50);
    }
  }, true);
  console.info('v424 dynamic creative cards UI loaded');
})();

/* MZJ v426 - dashboard content phase visibility: structure first, execution waiting after approval */
(function(){
  const VERSION = 'v426-content-structure-first-dashboard';
  try{ window.MZJ_APP_VERSION = VERSION; window.MZJ_LAST_PATCH = VERSION; }catch(_){ }
  function text(v){ try{ return normalizeText(v || ''); }catch(_){ return String(v == null ? '' : v).trim(); } }
  function key(v){
    try{ return identityClean(v || ''); }
    catch(_){ return text(v).replace(/[أإآٱ]/g,'ا').replace(/[ؤ]/g,'و').replace(/[ئ]/g,'ي').replace(/[ة]/g,'ه').replace(/[ى]/g,'ي').replace(/[ـ]/g,'').replace(/[^\u0600-\u06FFa-zA-Z0-9]+/g,'').toLowerCase(); }
  }
  function arr(v){ return Array.isArray(v) ? v : []; }
  function uniq(list){
    const seen = new Set();
    return (list || []).map(text).filter(Boolean).filter(v => { const k = key(v); if(!k || seen.has(k)) return false; seen.add(k); return true; });
  }
  function roleOf(task){
    try{ return normalizeDepartmentRole(task?.departmentRole || task?.assignedDepartmentRole || task?.contentSectionId || task?.assignedDepartmentId || task?.contentSectionName || task?.assignedDepartmentName || task?.departmentName || '') || ''; }
    catch(_){ return key(task?.departmentRole || task?.assignedDepartmentRole || task?.contentSectionId || task?.assignedDepartmentId || task?.contentSectionName || task?.assignedDepartmentName || task?.departmentName || ''); }
  }
  function taskKeys(task){
    return uniq([
      task?.assignedToId, task?.assignedToUid, task?.assigneeUid, task?.userId, task?.userUid,
      task?.assignedToEmail, task?.assigneeEmail, task?.userEmail,
      task?.assignedToName, task?.assigneeName, task?.userName, task?.displayName,
      ...arr(task?.assignedToSearch), ...arr(task?.searchKeys), ...arr(task?.userIds), ...arr(task?.userNames), ...arr(task?.userCodes)
    ]);
  }
  function currentKeys(){
    let ident = {};
    let record = {};
    try{ ident = typeof getCurrentUserIdentity === 'function' ? (getCurrentUserIdentity() || {}) : {}; }catch(_){ ident = {}; }
    try{ record = typeof findCurrentUserRecord === 'function' ? (findCurrentUserRecord() || {}) : {}; }catch(_){ record = {}; }
    return uniq([
      ident.uid, ident.id, ident.email, ident.name, ident.displayName,
      record.id, record.uid, record.email, record.name, record.displayName,
      window.currentUser?.uid, window.currentUser?.email, window.currentUser?.displayName,
      window.auth?.currentUser?.uid, window.auth?.currentUser?.email, window.auth?.currentUser?.displayName
    ]);
  }
  function overlaps(a, b){
    const set = new Set((a || []).map(key).filter(Boolean));
    return (b || []).some(v => set.has(key(v)));
  }
  function taskAssignedToCurrent(task, userKeys){
    try{ if(typeof currentUserMatchesTaskExact === 'function' && currentUserMatchesTaskExact(task)) return true; }catch(_){ }
    return overlaps(taskKeys(task), userKeys);
  }
  function allCampaignTasks(campaign){
    try{ return typeof tasksForCampaign === 'function' ? (tasksForCampaign(campaign) || []) : arr(campaign?.departmentTasks); }
    catch(_){ return arr(campaign?.departmentTasks); }
  }
  function taskCampaignId(task, campaign){ return text(task?.campaignId || task?.campaignDocId || task?.campaign_id || campaign?.id || campaign?.docId || ''); }
  function isStructureTask(task){
    const role = roleOf(task);
    const title = key([task?.taskType, task?.structureTaskLabel, task?.sourceRequestStep, task?.creative, task?.product].filter(Boolean).join(' '));
    return role === 'content' && !!(task?.needsStructureUpload || task?.structureRequestTask || task?.structureBundleTask || task?.sourceRequestStep === 'campaign_request_data' || title.includes(key('طلب هيكل')) || title.includes(key('هيكل حملة')));
  }
  function structureApproved(task){
    let structureStatus = '';
    try{ structureStatus = key((typeof taskStructure === 'function' ? taskStructure(task) : (task?.structure || {}))?.status || ''); }catch(_){ structureStatus = key(task?.structure?.status || ''); }
    const status = key(task?.status || task?.state || '');
    const templateStatus = key(task?.taskTemplate?.status || task?.contentTaskTemplate?.status || task?.approvedContentTemplate?.status || task?.contentTemplateStatus || '');
    const adminApproved = arr(task?.steps).some(step => step?.adminOnly && step?.done);
    const hasApprovedAttachment = !!(task?.structureApprovedAt || task?.structure?.approvedAt || task?.approvedAt);
    return adminApproved || hasApprovedAttachment || ['approved','distributed','done','completed','معتمد','مكتمل'].some(k => status.includes(key(k)) || structureStatus.includes(key(k)) || templateStatus.includes(key(k)));
  }
  function executionWaiting(task){
    const role = roleOf(task);
    if(!['design','montage','shooting'].includes(role)) return false;
    try{ if(typeof isTaskWaitingForDependency === 'function' && isTaskWaitingForDependency(task)) return true; }catch(_){ }
    const status = key(task?.status || task?.state || '');
    return !!(task?.waitingForApproval || task?.structureLinkPending || status.includes('waitingstructure') || status.includes('waitingcontentapproval') || status.includes('waiting'));
  }
  function dependencyKeys(task){
    return uniq([
      task?.linkedContentUserId, task?.linkedContentUserUid, task?.linkedContentUserName,
      task?.contentWriterId, task?.contentWriterUid, task?.contentWriterName,
      ...arr(task?.dependsOnContentUserIds), ...arr(task?.dependsOnContentUserNames),
      ...arr(task?.upstreamUserIds), ...arr(task?.upstreamUserNames),
      ...arr(task?.dependencyLinks).flatMap(link => [link?.contentUserId, link?.contentUserName, link?.writerId, link?.writerName, link?.userId, link?.userName])
    ]);
  }
  function uniqueTasks(list){
    const seen = new Set();
    return (list || []).filter(task => {
      const id = text(task?.id || task?.taskId || task?.taskNo || JSON.stringify([task?.campaignId, task?.campaignName, task?.assignedToId, task?.userId, task?.taskType, task?.linkedContentUserId, task?.contentDependencyKey]));
      if(!id || seen.has(id)) return false;
      seen.add(id);
      return true;
    });
  }

  const previousGetVisibleTasks = typeof getVisibleTasksForCurrentUser === 'function' ? getVisibleTasksForCurrentUser : null;
  if(previousGetVisibleTasks){
    getVisibleTasksForCurrentUser = function(){
      const base = previousGetVisibleTasks.apply(this, arguments) || [];
      try{ if(typeof isCurrentUserAdmin === 'function' && isCurrentUserAdmin()) return base; }catch(_){ }
      const me = currentKeys();
      if(!me.length) return base;

      const explicitStructureTasks = [];
      const pendingStructureByCampaign = new Map();
      try{
        (campaigns || []).forEach(campaign => {
          const cid = text(campaign?.id || campaign?.docId || '');
          allCampaignTasks(campaign).forEach(task => {
            if(!isStructureTask(task)) return;
            if(!taskAssignedToCurrent(task, me)) return;
            const fixed = { ...task, campaignId: taskCampaignId(task, campaign) || cid, departmentRole: 'content', assignedDepartmentRole: task.assignedDepartmentRole || 'content', needsStructureUpload: true };
            explicitStructureTasks.push(fixed);
            if(!structureApproved(fixed)){
              const owner = taskKeys(fixed).find(k => overlaps([k], me)) || me[0];
              pendingStructureByCampaign.set(`${fixed.campaignId || cid}::${key(owner)}`, true);
              pendingStructureByCampaign.set(`${fixed.campaignId || cid}::__any__`, true);
            }
          });
        });
      }catch(_){ }

      const combined = uniqueTasks([...base, ...explicitStructureTasks]);
      return combined.filter(task => {
        if(isStructureTask(task)) return true;
        if(!executionWaiting(task)) return true;
        const cid = text(task?.campaignId || task?.campaignDocId || '');
        if(!cid) return true;
        const deps = dependencyKeys(task);
        // لو التاسك التنفيذي مرتبط بنفس كاتب المحتوى ولسه هيكله لم يعتمد، لا يظهر له قبل تاسك الهيكل.
        if(deps.length && overlaps(deps, me)){
          const matchedKey = deps.find(d => overlaps([d], me));
          if(pendingStructureByCampaign.get(`${cid}::${key(matchedKey)}`) || pendingStructureByCampaign.get(`${cid}::__any__`)) return false;
        }
        // لو اليوزر عنده مسار محتوى pending في نفس الحملة، اخفي انتظار الأقسام التنفيذية لنفس الحملة حتى يعتمد الهيكل.
        if(pendingStructureByCampaign.get(`${cid}::__any__`)) return false;
        return true;
      });
    };
  }
  try{ if(typeof renderTasksPage === 'function') renderTasksPage(); if(typeof renderAdminDashboard === 'function') renderAdminDashboard(); }catch(_){ }
  console.info(`${VERSION} loaded`);
})();

/* MZJ v427 - strict content writer dashboard: hide execution tasks until that writer structure is admin-approved */
(function(){
  const VERSION = 'v427-strict-content-structure-first-dashboard';
  try{ window.MZJ_APP_VERSION = VERSION; window.MZJ_LAST_PATCH = VERSION; }catch(_){ }
  function raw(v){ return String(v == null ? '' : v).trim(); }
  function norm(v){
    try{ return identityClean(v || ''); }
    catch(_){ return raw(v).replace(/[أإآٱ]/g,'ا').replace(/[ؤ]/g,'و').replace(/[ئ]/g,'ي').replace(/[ة]/g,'ه').replace(/[ى]/g,'ي').replace(/[ـ]/g,'').replace(/[^\u0600-\u06FFa-zA-Z0-9]+/g,'').toLowerCase(); }
  }
  function arr(v){ return Array.isArray(v) ? v : []; }
  function uniq(list){
    const seen = new Set();
    return (list || []).map(raw).filter(Boolean).filter(v => { const k = norm(v); if(!k || seen.has(k)) return false; seen.add(k); return true; });
  }
  function roleOf(task){
    try{ return normalizeDepartmentRole(task?.departmentRole || task?.assignedDepartmentRole || task?.assignedDepartmentId || task?.contentSectionId || task?.departmentName || task?.assignedDepartmentName || task?.contentSectionName || '') || ''; }
    catch(_){ return norm(task?.departmentRole || task?.assignedDepartmentRole || task?.assignedDepartmentId || task?.contentSectionId || task?.departmentName || task?.assignedDepartmentName || task?.contentSectionName || ''); }
  }
  function isContentStructure(task){
    const role = roleOf(task);
    const title = norm([task?.taskType, task?.structureTaskLabel, task?.sourceRequestStep, task?.creative, task?.product].filter(Boolean).join(' '));
    return role === 'content' && !!(task?.needsStructureUpload || task?.structureRequestTask || task?.structureBundleTask || task?.sourceRequestStep === 'campaign_request_data' || title.includes(norm('طلب هيكل')) || title.includes(norm('هيكل حملة')));
  }
  function isExecutionRole(task){ return ['design','montage','shooting','photography','photo'].includes(roleOf(task)); }
  function userTokensFromTask(task){
    return uniq([
      task?.assignedToId, task?.assignedToUid, task?.assigneeUid, task?.userId, task?.userUid,
      task?.assignedToEmail, task?.assigneeEmail, task?.userEmail,
      task?.assignedToName, task?.assigneeName, task?.userName, task?.displayName,
      ...arr(task?.assignedToSearch), ...arr(task?.searchKeys), ...arr(task?.userIds), ...arr(task?.userNames), ...arr(task?.userCodes)
    ]);
  }
  function dependencyTokens(task){
    return uniq([
      task?.linkedContentUserId, task?.linkedContentUserUid, task?.linkedContentUserName,
      task?.contentWriterId, task?.contentWriterUid, task?.contentWriterName,
      task?.upstreamUserLabel,
      ...arr(task?.dependsOnContentUserIds), ...arr(task?.dependsOnContentUserNames),
      ...arr(task?.upstreamUserIds), ...arr(task?.upstreamUserNames),
      ...arr(task?.dependencyLinks).flatMap(link => [link?.contentUserId, link?.contentUserName, link?.writerId, link?.writerName, link?.userId, link?.userName])
    ]);
  }
  function currentUserTokens(){
    let ident = {}, rec = {};
    try{ ident = typeof getCurrentUserIdentity === 'function' ? (getCurrentUserIdentity() || {}) : {}; }catch(_){ }
    try{ rec = typeof findCurrentUserRecord === 'function' ? (findCurrentUserRecord() || {}) : {}; }catch(_){ }
    return uniq([
      ident.uid, ident.id, ident.email, ident.name, ident.displayName,
      rec.id, rec.uid, rec.email, rec.name, rec.displayName,
      window.currentUser?.uid, window.currentUser?.email, window.currentUser?.displayName,
      window.auth?.currentUser?.uid, window.auth?.currentUser?.email, window.auth?.currentUser?.displayName
    ]);
  }
  function overlap(a,b){ const set = new Set((a || []).map(norm).filter(Boolean)); return (b || []).some(v => set.has(norm(v))); }
  function assignedToMe(task, me){
    try{ if(typeof currentUserMatchesTaskExact === 'function' && currentUserMatchesTaskExact(task)) return true; }catch(_){ }
    return overlap(userTokensFromTask(task), me);
  }
  function campaignKeysFrom(task, campaign){
    return uniq([
      campaign?.id, campaign?.docId, campaign?.campaignId, campaign?.campaignCode, campaign?.campaign_code, campaign?.campaignName, campaign?.campaign_name, campaign?.name,
      task?.campaignId, task?.campaignDocId, task?.campaign_id, task?.campaignCode, task?.campaign_code, task?.campaignName, task?.campaign_name, task?.campaignCreativeCode, task?.creativeLinkCode
    ]);
  }
  function allCampaignTasks(campaign){
    try{ return typeof tasksForCampaign === 'function' ? (tasksForCampaign(campaign) || []) : arr(campaign?.departmentTasks); }
    catch(_){ return arr(campaign?.departmentTasks); }
  }
  function structureApproved(task){
    let struct = {};
    try{ struct = typeof taskStructure === 'function' ? (taskStructure(task) || {}) : (task?.structure || {}); }catch(_){ struct = task?.structure || {}; }
    const statuses = [task?.status, task?.state, struct?.status, struct?.reviewStatus, task?.structureStatus, task?.contentStructureStatus].map(norm);
    const adminApproved = arr(task?.steps).some(step => step?.adminOnly && step?.done && norm(step?.label || '').includes(norm('اعتماد')));
    const approvedFlag = !!(task?.structureApprovedAt || task?.approvedAt || struct?.approvedAt || struct?.reviewedAt && statuses.some(s => s.includes('approved') || s.includes(norm('معتمد'))));
    return adminApproved || approvedFlag || statuses.some(s => s.includes('approved') || s.includes('distributed') || s.includes(norm('معتمد')));
  }
  function taskUniqueId(task, index){
    return raw(task?.id || task?.taskId || task?.taskIndex || task?.code || [task?.campaignId, task?.campaignName, task?.assignedToId, task?.userId, task?.departmentRole, task?.taskType, task?.linkedContentUserId, index].join('|'));
  }
  function uniqueTasks(list){
    const seen = new Set();
    return (list || []).filter((task, index) => { const id = taskUniqueId(task, index); if(seen.has(id)) return false; seen.add(id); return true; });
  }

  const prev = typeof getVisibleTasksForCurrentUser === 'function' ? getVisibleTasksForCurrentUser : null;
  if(prev){
    getVisibleTasksForCurrentUser = function(){
      const base = prev.apply(this, arguments) || [];
      try{ if(typeof isCurrentUserAdmin === 'function' && isCurrentUserAdmin()) return base; }catch(_){ }
      const me = currentUserTokens();
      if(!me.length) return base;

      const structureTasks = [];
      const pendingCampaignKeys = new Set();
      const pendingWriterCampaignKeys = new Set();

      try{
        (campaigns || []).forEach(campaign => {
          allCampaignTasks(campaign).forEach(task => {
            if(!isContentStructure(task)) return;
            if(!assignedToMe(task, me)) return;
            const fixed = { ...task, departmentRole: 'content', assignedDepartmentRole: task.assignedDepartmentRole || 'content', needsStructureUpload: true };
            const cKeys = campaignKeysFrom(fixed, campaign).map(norm).filter(Boolean);
            const ownerKeys = userTokensFromTask(fixed).filter(k => overlap([k], me)).map(norm);
            structureTasks.push(fixed);
            if(!structureApproved(fixed)){
              cKeys.forEach(ck => pendingCampaignKeys.add(ck));
              cKeys.forEach(ck => (ownerKeys.length ? ownerKeys : me).forEach(ok => pendingWriterCampaignKeys.add(`${ck}::${norm(ok)}`)));
            }
          });
        });
      }catch(error){ console.warn('v427 structure scan failed', error); }

      const combined = uniqueTasks([...base, ...structureTasks]);
      return combined.filter(task => {
        if(isContentStructure(task)) return true;
        if(!isExecutionRole(task)) return true;
        const cKeys = campaignKeysFrom(task, null).map(norm).filter(Boolean);
        if(!cKeys.length) return true;
        const hasPendingContentPath = cKeys.some(ck => pendingCampaignKeys.has(ck));
        if(!hasPendingContentPath) return true;
        const deps = dependencyTokens(task);
        const depMatchesMe = deps.length ? overlap(deps, me) : false;
        const assignedMatchesMe = assignedToMe(task, me);
        const writerSpecificPending = deps.length && deps.some(d => cKeys.some(ck => pendingWriterCampaignKeys.has(`${ck}::${norm(d)}`)));
        // لو اليوزر له تاسك هيكل pending في نفس الحملة، نخفي أي تاسك تنفيذي متعلق بيه أو مسند له لحد اعتماد الهيكل.
        if(depMatchesMe || assignedMatchesMe || writerSpecificPending) return false;
        return true;
      });
    };
  }
  try{ if(typeof renderTasksPage === 'function') renderTasksPage(); if(typeof renderAdminDashboard === 'function') renderAdminDashboard(); }catch(_){ }
  console.info(`${VERSION} loaded`);
})();

/* MZJ v428 - hard gate execution waiting tasks when current user still has pending content structure in same campaign */
(function(){
  const VERSION = 'v428-content-structure-hard-gate-dashboard';
  try{ window.MZJ_APP_VERSION = VERSION; window.MZJ_LAST_PATCH = VERSION; }catch(_){ }
  function text(v){ return String(v == null ? '' : v).trim(); }
  function norm(v){
    try{ return identityClean(v || ''); }
    catch(_){ return text(v).replace(/[أإآٱ]/g,'ا').replace(/[ؤ]/g,'و').replace(/[ئ]/g,'ي').replace(/[ة]/g,'ه').replace(/[ى]/g,'ي').replace(/[ـ]/g,'').replace(/[^\u0600-\u06FFa-zA-Z0-9]+/g,'').toLowerCase(); }
  }
  function arr(v){ return Array.isArray(v) ? v : []; }
  function unique(list){
    const seen = new Set();
    return (list || []).flat().map(text).filter(Boolean).filter(v => { const k = norm(v); if(!k || seen.has(k)) return false; seen.add(k); return true; });
  }
  function overlap(a,b){ const set = new Set((a || []).map(norm).filter(Boolean)); return (b || []).some(v => set.has(norm(v))); }
  function roleOf(task){
    try{ return normalizeDepartmentRole(task?.departmentRole || task?.assignedDepartmentRole || task?.assignedDepartmentId || task?.departmentId || task?.contentSectionId || task?.departmentCode || task?.assignedDepartmentName || task?.departmentName || task?.contentSectionName || '') || ''; }
    catch(_){ return norm(task?.departmentRole || task?.assignedDepartmentRole || task?.assignedDepartmentId || task?.departmentId || task?.contentSectionId || task?.departmentCode || task?.assignedDepartmentName || task?.departmentName || task?.contentSectionName || ''); }
  }
  function taskUserTokens(task){
    return unique([
      task?.assignedToId, task?.assignedToUid, task?.assigneeUid, task?.assigneeId, task?.userId, task?.userUid,
      task?.assignedToEmail, task?.assigneeEmail, task?.userEmail,
      task?.assignedToName, task?.assigneeName, task?.userName, task?.displayName,
      arr(task?.assignedToSearch), arr(task?.searchKeys), arr(task?.userIds), arr(task?.userNames), arr(task?.userCodes)
    ]);
  }
  function dependencyTokens(task){
    return unique([
      task?.linkedContentUserId, task?.linkedContentUserUid, task?.linkedContentUserName,
      task?.contentWriterId, task?.contentWriterUid, task?.contentWriterName,
      task?.writerId, task?.writerName, task?.contentDependencyKey, task?.upstreamUserLabel,
      arr(task?.dependsOnContentUserIds), arr(task?.dependsOnContentUserNames),
      arr(task?.upstreamUserIds), arr(task?.upstreamUserNames),
      arr(task?.contentWritingDeadlines).flatMap(x => [x?.contentUserId, x?.contentUserName, x?.writerId, x?.writerName]),
      arr(task?.contentWriterDeadlines).flatMap(x => [x?.contentUserId, x?.contentUserName, x?.writerId, x?.writerName]),
      arr(task?.dependencyLinks).flatMap(x => [x?.contentUserId, x?.contentUserName, x?.writerId, x?.writerName, x?.userId, x?.userName])
    ]);
  }
  function currentTokensFromSession(){
    let ident = {}, rec = {}, authUser = {};
    try{ ident = typeof getCurrentUserIdentity === 'function' ? (getCurrentUserIdentity() || {}) : {}; }catch(_){ }
    try{ rec = typeof findCurrentUserRecord === 'function' ? (findCurrentUserRecord() || {}) : {}; }catch(_){ }
    try{ authUser = window.auth?.currentUser || window.currentUser || {}; }catch(_){ }
    return unique([
      ident.uid, ident.id, ident.email, ident.name, ident.displayName,
      rec.id, rec.uid, rec.email, rec.name, rec.displayName, rec.code, rec.userCode,
      arr(rec?.userCodes), arr(rec?.codes), arr(rec?.searchKeys),
      authUser.uid, authUser.email, authUser.displayName
    ]);
  }
  function currentUserMatches(task, me){
    try{ if(typeof currentUserMatchesTaskExact === 'function' && currentUserMatchesTaskExact(task)) return true; }catch(_){ }
    return overlap(taskUserTokens(task), me);
  }
  function campaignTokens(campaign, task){
    return unique([
      campaign?.id, campaign?.docId, campaign?.campaignId, campaign?.campaignCode, campaign?.campaign_code, campaign?.name, campaign?.campaignName, campaign?.campaign_name,
      task?.campaignId, task?.campaignDocId, task?.campaign_id, task?.campaignCode, task?.campaign_code, task?.campaignName, task?.campaign_name, task?.campaignCreativeCode, task?.creativeLinkCode
    ]).map(norm).filter(Boolean);
  }
  function isStructureTask(task){
    const r = roleOf(task);
    const line = norm([task?.taskType, task?.structureTaskLabel, task?.sourceRequestStep, task?.product, task?.creative].filter(Boolean).join(' '));
    return r === 'content' && !!(task?.needsStructureUpload || task?.structureRequestTask || task?.structureBundleTask || task?.sourceRequestStep === 'campaign_request_data' || line.includes(norm('طلب هيكل')) || line.includes(norm('هيكل حملة')));
  }
  function isExecutionTask(task){ return ['design','montage','shooting','photography','photo'].includes(roleOf(task)); }
  function isWaitingForStructure(task){
    const st = norm([task?.status, task?.state, task?.taskStatus, task?.waitingForApprovalLabel].filter(Boolean).join(' '));
    let dep = false;
    try{ dep = typeof isTaskWaitingForDependency === 'function' && isTaskWaitingForDependency(task); }catch(_){ }
    return !!(dep || task?.waitingForApproval || task?.deferredDeadlineUntilContentApproval || st.includes('waitingstructure') || st.includes('waitingcontentapproval') || st.includes(norm('في انتظار اعتماد الهيكل')));
  }
  function isStructureApproved(task){
    let structure = {};
    try{ structure = typeof taskStructure === 'function' ? (taskStructure(task) || {}) : (task?.structure || {}); }catch(_){ structure = task?.structure || {}; }
    const st = norm([task?.status, task?.state, task?.structureStatus, task?.contentStructureStatus, structure?.status, structure?.reviewStatus].filter(Boolean).join(' '));
    const approvedStep = arr(task?.steps).some(step => step?.adminOnly && step?.done && norm(step?.label || '').includes(norm('اعتماد')));
    return !!(approvedStep || task?.structureApprovedAt || task?.approvedAt || structure?.approvedAt || st.includes('approved') || st.includes('distributed') || st.includes(norm('معتمد')));
  }
  function rawTasksForCampaign(campaign){
    const out = [];
    const seen = new Set();
    function push(t){
      if(!t || typeof t !== 'object') return;
      const fixed = { ...t, campaignId: t.campaignId || campaign?.id || campaign?.campaignId || campaign?.campaignCode || campaign?.campaign_code, campaignName: t.campaignName || campaign?.campaignName || campaign?.name || campaign?.campaign_name, campaignCode: t.campaignCode || campaign?.campaignCode || campaign?.campaign_code };
      const id = text(fixed.id || fixed.taskId || fixed.taskIndex || [fixed.campaignId, fixed.assignedToId, fixed.userId, fixed.departmentRole, fixed.assignedDepartmentRole, fixed.taskType, fixed.linkedContentUserId, out.length].join('|'));
      if(seen.has(id)) return;
      seen.add(id);
      out.push(fixed);
    }
    arr(campaign?.departmentTasks).forEach(push);
    arr(campaign?.tasks).forEach(push);
    return out;
  }
  function taskId(task, index){ return text(task?.id || task?.taskId || task?.taskIndex || [task?.campaignId, task?.campaignName, task?.assignedToId, task?.userId, task?.departmentRole, task?.assignedDepartmentRole, task?.taskType, task?.linkedContentUserId, index].join('|')); }
  function uniqueTasks(list){
    const seen = new Set();
    return (list || []).filter((task,index) => { const id = taskId(task,index); if(seen.has(id)) return false; seen.add(id); return true; });
  }

  const previous = typeof getVisibleTasksForCurrentUser === 'function' ? getVisibleTasksForCurrentUser : null;
  if(previous){
    getVisibleTasksForCurrentUser = function(){
      const base = previous.apply(this, arguments) || [];
      try{ if(typeof isCurrentUserAdmin === 'function' && isCurrentUserAdmin()) return base; }catch(_){ }

      let me = currentTokensFromSession();
      // مهم: لو السيشن ناقص، التاسكات الظاهرة أصلاً تخص اليوزر الحالي، فنستخرج منها هوية اليوزر.
      me = unique([me, base.flatMap(task => taskUserTokens(task))]);
      if(!me.length) return base;

      const ownPendingStructureCampaigns = new Set();
      const ownPendingWriterCampaigns = new Set();
      const ownStructureTasks = [];

      try{
        (campaigns || []).forEach(campaign => {
          const cRawTasks = rawTasksForCampaign(campaign);
          cRawTasks.forEach(task => {
            if(!isStructureTask(task)) return;
            if(!currentUserMatches(task, me)) return;
            const fixed = { ...task, departmentRole:'content', assignedDepartmentRole: task.assignedDepartmentRole || 'content', needsStructureUpload:true };
            ownStructureTasks.push(fixed);
            if(isStructureApproved(fixed)) return;
            const cKeys = campaignTokens(campaign, fixed);
            const ownerKeys = taskUserTokens(fixed).filter(k => overlap([k], me));
            cKeys.forEach(ck => ownPendingStructureCampaigns.add(ck));
            cKeys.forEach(ck => (ownerKeys.length ? ownerKeys : me).forEach(ok => ownPendingWriterCampaigns.add(`${ck}::${norm(ok)}`)));
          });
        });
      }catch(error){ console.warn(VERSION, 'pending structure scan failed', error); }

      const combined = uniqueTasks([...base, ...ownStructureTasks]);
      return combined.filter(task => {
        if(isStructureTask(task)) return true;
        if(!isExecutionTask(task)) return true;
        if(!isWaitingForStructure(task)) return true;
        const cKeys = campaignTokens(null, task);
        if(!cKeys.some(ck => ownPendingStructureCampaigns.has(ck))) return true;
        const taskIsMine = currentUserMatches(task, me);
        const deps = dependencyTokens(task);
        const dependsOnMe = deps.length ? overlap(deps, me) : false;
        const writerStillPending = deps.some(d => cKeys.some(ck => ownPendingWriterCampaigns.has(`${ck}::${norm(d)}`)));
        // طالما لهذا اليوزر تاسك هيكل pending في نفس الحملة، أي تنفيذ waiting_structure مسند له أو تابع له يختفي.
        if(taskIsMine || dependsOnMe || writerStillPending) return false;
        return true;
      });
    };
  }
  try{ if(typeof renderTasksPage === 'function') renderTasksPage(); if(typeof renderAdminDashboard === 'function') renderAdminDashboard(); }catch(_){ }
  console.info(`${VERSION} loaded`);
})();

/* MZJ v429 - robust content structure dashboard visibility by writer assignment */
(function(){
  const VERSION = 'v429-robust-content-structure-dashboard';
  try{ window.MZJ_APP_VERSION = VERSION; window.MZJ_LAST_PATCH = VERSION; }catch(_){ }
  function raw(v){ return String(v == null ? '' : v).trim(); }
  function norm(v){
    try{ return identityClean(v || ''); }
    catch(_){ return raw(v).replace(/[أإآٱ]/g,'ا').replace(/[ؤ]/g,'و').replace(/[ئ]/g,'ي').replace(/[ة]/g,'ه').replace(/[ى]/g,'ي').replace(/[ـ]/g,'').replace(/[^\u0600-\u06FFa-zA-Z0-9]+/g,'').toLowerCase(); }
  }
  function arr(v){ return Array.isArray(v) ? v : []; }
  function flat(v){
    if(v == null) return [];
    if(Array.isArray(v)) return v.flatMap(flat);
    if(typeof v === 'object'){
      return [v.id, v.uid, v.email, v.emailLower, v.name, v.displayName, v.username, v.code, v.userCode, v.shortCode, v.userId, v.userUid, v.userEmail, v.userName, v.assignedToId, v.assignedToUid, v.assignedToEmail, v.assignedToName, v.assigneeId, v.assigneeUid, v.assigneeEmail, v.assigneeName, v.userIds, v.userNames, v.userEmails, v.userCodes, v.searchKeys, v.assignedToSearch].flatMap(flat);
    }
    return [v];
  }
  function uniq(list){
    const seen = new Set();
    return flat(list).map(raw).filter(Boolean).filter(v => { const k = norm(v); if(!k || seen.has(k)) return false; seen.add(k); return true; });
  }
  function overlap(a,b){ const set = new Set(uniq(a).map(norm)); return uniq(b).some(v => set.has(norm(v))); }
  function roleOf(task){
    try{ return normalizeDepartmentRole(task?.departmentRole || task?.assignedDepartmentRole || task?.assignedDepartmentId || task?.departmentId || task?.contentSectionId || task?.departmentCode || task?.assignedDepartmentName || task?.departmentName || task?.contentSectionName || '') || ''; }
    catch(_){ return norm(task?.departmentRole || task?.assignedDepartmentRole || task?.assignedDepartmentId || task?.departmentId || task?.contentSectionId || task?.departmentCode || task?.assignedDepartmentName || task?.departmentName || task?.contentSectionName || ''); }
  }
  function isContentStructureTask(task){
    const r = roleOf(task);
    const line = norm([task?.taskType, task?.structureTaskLabel, task?.sourceRequestStep, task?.creative, task?.product, task?.contentSectionName, task?.assignedDepartmentName].filter(Boolean).join(' '));
    return r === 'content' && !!(task?.needsStructureUpload || task?.structureRequestTask || task?.structureBundleTask || task?.sourceRequestStep === 'campaign_request_data' || line.includes(norm('طلب هيكل')) || line.includes(norm('هيكل حملة')) || line.includes('structure'));
  }
  function isExecTask(task){ return ['design','montage','shooting','photography','photo'].includes(roleOf(task)); }
  function userTokensFromTask(task){
    return uniq([task?.assignedToId, task?.assignedToUid, task?.assigneeId, task?.assigneeUid, task?.userId, task?.userUid, task?.uid, task?.assignedToEmail, task?.assigneeEmail, task?.userEmail, task?.email, task?.assignedToName, task?.assigneeName, task?.userName, task?.displayName, task?.name, task?.username, task?.assignedToSearch, task?.searchKeys, task?.userIds, task?.userNames, task?.userEmails, task?.userCodes]);
  }
  function currentTokens(){
    let ident = {}, rec = {}, session = {}, authUser = {};
    try{ ident = typeof getCurrentUserIdentity === 'function' ? (getCurrentUserIdentity() || {}) : {}; }catch(_){ }
    try{ rec = typeof findCurrentUserRecord === 'function' ? (findCurrentUserRecord() || {}) : {}; }catch(_){ }
    try{ session = typeof getCurrentUser === 'function' ? (getCurrentUser() || {}) : {}; }catch(_){ }
    try{ authUser = mainAuth?.currentUser || window.auth?.currentUser || window.currentUser || {}; }catch(_){ }
    let related = [];
    try{ related = typeof currentUserRelatedRecords === 'function' ? (currentUserRelatedRecords() || []) : []; }catch(_){ }
    const local = [];
    try{
      local.push(localStorage.getItem('mzj_login_email') || '');
      local.push(localStorage.getItem('mzj_user_email') || '');
      local.push(localStorage.getItem('mzj_current_user') || '');
    }catch(_){ }
    return uniq([ident, rec, session, authUser, related, local]);
  }
  function writerEntriesFromAssignment(assignment){
    if(!assignment || typeof assignment !== 'object') return [];
    const ids = arr(assignment.userIds || assignment.assignedUserIds || assignment.memberIds);
    const names = arr(assignment.userNames || assignment.assignedUserNames || assignment.memberNames);
    const emails = arr(assignment.userEmails || assignment.assignedUserEmails || assignment.memberEmails);
    const codes = arr(assignment.userCodes || assignment.assignedUserCodes || assignment.memberCodes);
    const max = Math.max(ids.length, names.length, emails.length, codes.length);
    if(!max) return [];
    const out = [];
    for(let i = 0; i < max; i += 1){
      const base = [ids[i], names[i], emails[i], codes[i]];
      let user = {};
      try{ user = typeof findUserByAnyIdentity === 'function' ? (findUserByAnyIdentity(base) || {}) : {}; }catch(_){ }
      out.push({ index:i, tokens:uniq([base, user]) });
    }
    return out;
  }
  function contentWriterEntries(campaign){
    const entries = [];
    const rootAssignments = [campaign?.departmentAssignments?.content, campaign?.departmentAssignments?.CONTENT, campaign?.contentAssignment, campaign?.writerAssignment];
    rootAssignments.forEach(a => entries.push(...writerEntriesFromAssignment(a)));
    arr(campaign?.creatives).forEach(row => {
      const assignments = row?.departmentAssignments || {};
      entries.push(...writerEntriesFromAssignment(assignments.content || assignments.CONTENT || row?.contentAssignment || row?.writerAssignment));
      arr(row?.tasks).filter(t => roleOf(t) === 'content' || t?.needsStructureUpload).forEach(t => entries.push(...writerEntriesFromAssignment(t)));
    });
    arr(campaign?.departmentTasks).filter(isContentStructureTask).forEach(t => entries.push({ index: entries.length, tokens:userTokensFromTask(t) }));
    const seen = new Set();
    return entries.filter(entry => {
      const k = uniq(entry.tokens).map(norm).sort().join('|');
      if(!k || seen.has(k)) return false;
      seen.add(k);
      return true;
    });
  }
  function myWriterTokensForCampaign(campaign, me){
    const mine = contentWriterEntries(campaign).filter(entry => overlap(entry.tokens, me));
    return uniq([me, mine.flatMap(entry => entry.tokens)]);
  }
  function campaignTokens(campaign, task){
    return uniq([campaign?.id, campaign?.docId, campaign?.campaignId, campaign?.campaignCode, campaign?.campaign_code, campaign?.name, campaign?.campaignName, campaign?.campaign_name, task?.campaignId, task?.campaignDocId, task?.campaign_id, task?.campaignCode, task?.campaign_code, task?.campaignName, task?.campaign_name, task?.campaignCreativeCode, task?.creativeLinkCode]).map(norm).filter(Boolean);
  }
  function allRawCampaignTasks(campaign){
    const result = [];
    const seen = new Set();
    function push(task){
      if(!task || typeof task !== 'object') return;
      const fixed = { ...task, campaignId: task.campaignId || campaign?.id || campaign?.docId || campaign?.campaignId || campaign?.campaignCode || campaign?.campaign_code || '', campaignName: task.campaignName || campaign?.campaignName || campaign?.campaign_name || campaign?.name || '', campaignCode: task.campaignCode || campaign?.campaignCode || campaign?.campaign_code || '' };
      const id = raw(fixed.id || fixed.taskId || fixed.taskIndex || [fixed.campaignId, fixed.assignedToId, fixed.userId, fixed.departmentRole, fixed.assignedDepartmentRole, fixed.taskType, fixed.linkedContentUserId, result.length].join('|'));
      if(seen.has(id)) return;
      seen.add(id);
      result.push(fixed);
    }
    try{ (typeof tasksForCampaign === 'function' ? tasksForCampaign(campaign) : []).forEach(push); }catch(_){ }
    arr(campaign?.departmentTasks).forEach(push);
    arr(campaign?.tasks).forEach(push);
    return result;
  }
  function structureApproved(task){
    let s = {};
    try{ s = typeof taskStructure === 'function' ? (taskStructure(task) || {}) : (task?.structure || {}); }catch(_){ s = task?.structure || {}; }
    const st = norm([task?.status, task?.state, task?.taskStatus, task?.structureStatus, task?.contentStructureStatus, s?.status, s?.reviewStatus].filter(Boolean).join(' '));
    const approvedStep = arr(task?.steps).some(step => step?.adminOnly && step?.done && norm(step?.label || '').includes(norm('اعتماد')));
    return !!(approvedStep || task?.structureApprovedAt || task?.approvedAt || s?.approvedAt || st.includes('approved') || st.includes('distributed') || st.includes(norm('معتمد')));
  }
  function isWaitingForStructure(task){
    let dep = false;
    try{ dep = typeof isTaskWaitingForDependency === 'function' && isTaskWaitingForDependency(task); }catch(_){ }
    const st = norm([task?.status, task?.state, task?.taskStatus, task?.waitingForApprovalLabel].filter(Boolean).join(' '));
    return !!(dep || task?.waitingForApproval || task?.structureLinkPending || task?.deferredDeadlineUntilContentApproval || st.includes('waitingstructure') || st.includes('waitingcontentapproval') || st.includes('waiting') || st.includes(norm('في انتظار اعتماد الهيكل')));
  }
  function dependencyTokens(task){
    return uniq([task?.linkedContentUserId, task?.linkedContentUserUid, task?.linkedContentUserName, task?.contentWriterId, task?.contentWriterUid, task?.contentWriterName, task?.writerId, task?.writerName, task?.contentDependencyKey, task?.upstreamUserLabel, task?.dependsOnContentUserIds, task?.dependsOnContentUserNames, task?.upstreamUserIds, task?.upstreamUserNames, arr(task?.dependencyLinks).flatMap(x => [x?.contentUserId, x?.contentUserName, x?.writerId, x?.writerName, x?.userId, x?.userName])]);
  }
  function uniqueTasks(list){
    const seen = new Set();
    return (list || []).filter((task, index) => {
      const id = raw(task?.id || task?.taskId || [task?.campaignId, task?.campaignName, task?.assignedToId, task?.userId, task?.departmentRole, task?.taskType, task?.linkedContentUserId, index].join('|'));
      if(seen.has(id)) return false;
      seen.add(id);
      return true;
    });
  }

  const prevGetVisible = typeof getVisibleTasksForCurrentUser === 'function' ? getVisibleTasksForCurrentUser : null;
  if(prevGetVisible){
    getVisibleTasksForCurrentUser = function(){
      const base = prevGetVisible.apply(this, arguments) || [];
      try{ if(typeof isCurrentUserAdmin === 'function' && isCurrentUserAdmin()) return base; }catch(_){ }
      const me = uniq([currentTokens(), base.flatMap(userTokensFromTask)]);
      if(!me.length) return base;
      const ownStructureTasks = [];
      const pendingCampaigns = new Set();
      const pendingWriters = new Set();
      try{
        (campaigns || []).forEach(campaign => {
          const writerTokens = myWriterTokensForCampaign(campaign, me);
          if(!writerTokens.length) return;
          allRawCampaignTasks(campaign).forEach(task => {
            if(!isContentStructureTask(task)) return;
            if(!overlap(userTokensFromTask(task), writerTokens)) return;
            const fixed = { ...task, campaignId: task.campaignId || campaign?.id || campaign?.docId || campaign?.campaignId || '', campaignName: task.campaignName || campaign?.campaignName || campaign?.name || '', campaignCode: task.campaignCode || campaign?.campaignCode || campaign?.campaign_code || '', departmentRole:'content', assignedDepartmentRole: task.assignedDepartmentRole || 'content', assignedDepartmentId: task.assignedDepartmentId || task.contentSectionId || 'content', assignedDepartmentName: task.assignedDepartmentName || task.contentSectionName || 'قسم المحتوى', needsStructureUpload:true, structureRequestTask:true };
            ownStructureTasks.push(fixed);
            if(!structureApproved(fixed)){
              const cKeys = campaignTokens(campaign, fixed);
              const ownerKeys = userTokensFromTask(fixed).filter(k => overlap([k], writerTokens));
              cKeys.forEach(ck => pendingCampaigns.add(ck));
              cKeys.forEach(ck => (ownerKeys.length ? ownerKeys : writerTokens).forEach(ok => pendingWriters.add(`${ck}::${norm(ok)}`)));
            }
          });
        });
      }catch(error){ console.warn(VERSION, 'structure visibility scan failed', error); }
      return uniqueTasks([...ownStructureTasks, ...base]).filter(task => {
        if(isContentStructureTask(task)) return true;
        if(!isExecTask(task) || !isWaitingForStructure(task)) return true;
        const cKeys = campaignTokens(null, task);
        if(!cKeys.some(ck => pendingCampaigns.has(ck))) return true;
        const deps = dependencyTokens(task);
        const taskIsMine = overlap(userTokensFromTask(task), me);
        const dependsOnMe = deps.length ? overlap(deps, me) : false;
        const writerPending = deps.some(d => cKeys.some(ck => pendingWriters.has(`${ck}::${norm(d)}`)));
        if(taskIsMine || dependsOnMe || writerPending) return false;
        return true;
      });
    };
  }

  const prevShortTaskName = typeof shortTaskName === 'function' ? shortTaskName : null;
  if(prevShortTaskName){
    shortTaskName = function(task){
      try{
        if(isContentStructureTask(task)){
          const creative = raw(task?.structureCreativeLabel || task?.creative || task?.product || task?.taskType || '').replace(/^طلب\s*هيكل\s*-?\s*/,'');
          const label = raw(task?.taskType || '').includes('طلب') ? task.taskType : `طلب هيكل${creative ? ' - ' + creative : ''}`;
          return escapeHtml(label);
        }
      }catch(_){ }
      return prevShortTaskName.apply(this, arguments);
    };
  }

  try{ if(typeof renderTasksPage === 'function') renderTasksPage(); if(typeof renderAdminDashboard === 'function') renderAdminDashboard(); }catch(_){ }
  console.info(`${VERSION} loaded`);
})();

/* MZJ v430 - exact content structure owner visibility + detail open fix */
(function(){
  const VERSION = 'v430-exact-content-structure-owner-detail-fix';
  try{ window.MZJ_APP_VERSION = VERSION; window.MZJ_LAST_PATCH = VERSION; }catch(_){ }
  function raw(v){ return String(v == null ? '' : v).trim(); }
  function norm(v){
    try{ return identityClean(v || ''); }
    catch(_){ return raw(v).replace(/[ً-ٰٟ]/g,'').replace(/[أإآٱا]/g,'ا').replace(/[ؤ]/g,'و').replace(/[ئىي]/g,'ي').replace(/[ة]/g,'ه').replace(/[ـ]/g,'').replace(/[\s_\-.@]+/g,'').toLowerCase(); }
  }
  function arr(v){ return Array.isArray(v) ? v : []; }
  function flat(v){
    if(v == null) return [];
    if(Array.isArray(v)) return v.flatMap(flat);
    if(typeof v === 'object'){
      return [
        v.id, v.uid, v.email, v.emailLower, v.name, v.displayName, v.username,
        v.userId, v.userUid, v.userEmail, v.userName,
        v.assigneeId, v.assigneeUid, v.assigneeEmail, v.assigneeName,
        v.assignedToId, v.assignedToUid, v.assignedToEmail, v.assignedToName,
        v.searchKeys, v.assignedToSearch, v.userIds, v.userNames, v.userEmails
      ].flatMap(flat);
    }
    return [v];
  }
  function uniq(values){
    const seen = new Set();
    return flat(values).map(raw).filter(Boolean).filter(v => { const k = norm(v); if(!k || seen.has(k)) return false; seen.add(k); return true; });
  }
  function overlap(a,b){ const set = new Set(uniq(a).map(norm)); return uniq(b).some(v => set.has(norm(v))); }
  function currentOnlyTokens(){
    const out = [];
    try{ out.push(typeof currentUserIdentityKeys === 'function' ? currentUserIdentityKeys() : []); }catch(_){ }
    try{ out.push(typeof getCurrentUserIdentity === 'function' ? (getCurrentUserIdentity() || {}) : {}); }catch(_){ }
    try{ out.push(typeof findCurrentUserRecord === 'function' ? (findCurrentUserRecord() || {}) : {}); }catch(_){ }
    try{ out.push(typeof getCurrentUser === 'function' ? (getCurrentUser() || {}) : {}); }catch(_){ }
    try{ out.push(mainAuth?.currentUser || window.auth?.currentUser || window.currentUser || {}); }catch(_){ }
    try{ out.push(localStorage.getItem('mzj_login_email') || '', localStorage.getItem('mzj_user_email') || ''); }catch(_){ }
    return uniq(out);
  }
  function roleOf(task){
    try{ return normalizeDepartmentRole(task?.departmentRole || task?.assignedDepartmentRole || task?.assignedDepartmentId || task?.departmentId || task?.contentSectionId || task?.assignedDepartmentName || task?.departmentName || task?.contentSectionName || '') || ''; }
    catch(_){ return norm(task?.departmentRole || task?.assignedDepartmentRole || task?.assignedDepartmentId || task?.departmentId || task?.contentSectionId || task?.assignedDepartmentName || task?.departmentName || task?.contentSectionName || ''); }
  }
  function isContentStructureTask(task){
    const r = roleOf(task);
    const line = norm([task?.taskType, task?.structureTaskLabel, task?.sourceRequestStep, task?.creative, task?.product, task?.contentSectionName, task?.assignedDepartmentName].filter(Boolean).join(' '));
    return r === 'content' && !!(task?.needsStructureUpload || task?.structureRequestTask || task?.structureBundleTask || task?.sourceRequestStep === 'campaign_request_data' || line.includes(norm('طلب هيكل')) || line.includes(norm('هيكل حملة')) || line.includes('structure'));
  }
  function taskOwnerTokens(task){
    return uniq([task?.assignedToId, task?.assignedToUid, task?.assigneeId, task?.assigneeUid, task?.userId, task?.userUid, task?.uid, task?.assignedToEmail, task?.assigneeEmail, task?.userEmail, task?.email, task?.assignedToName, task?.assigneeName, task?.userName, task?.displayName, task?.name, task?.username, task?.assignedToSearch, task?.searchKeys, task?.userIds, task?.userNames, task?.userEmails]);
  }
  function taskIdMatch(task, taskId, campaignId){
    const wanted = norm(taskId || '');
    if(!wanted) return false;
    const ids = uniq([task?.id, task?.taskId, task?.docId, task?.taskNo, task?.structureTaskNo, task?.linkedExecutionTaskId, task?.parentStructureTaskId]).map(norm);
    if(!ids.includes(wanted)) return false;
    const c = norm(campaignId || '');
    if(!c) return true;
    return uniq([task?.campaignId, task?.campaignDocId, task?.campaign_id, task?.campaignCode, task?.campaign_code]).map(norm).includes(c);
  }

  const prevGetVisible = typeof getVisibleTasksForCurrentUser === 'function' ? getVisibleTasksForCurrentUser : null;
  if(prevGetVisible){
    getVisibleTasksForCurrentUser = function(){
      const list = prevGetVisible.apply(this, arguments) || [];
      try{ if(typeof isCurrentUserAdmin === 'function' && isCurrentUserAdmin()) return list; }catch(_){ }
      const me = currentOnlyTokens();
      if(!me.length) return list;
      return list.filter(task => {
        if(!isContentStructureTask(task)) return true;
        // مهم: تاسك الهيكل يظهر لصاحب الإسناد فقط. لا نستخدم تاسكات ظاهرة سابقا كمفاتيح هوية،
        // لأن ده كان بيخلي أحمد يشوف تاسك بلال والعكس.
        return overlap(taskOwnerTokens(task), me);
      });
    };
  }

  const prevRenderTaskDetail = typeof renderTaskDetail === 'function' ? renderTaskDetail : null;
  if(prevRenderTaskDetail){
    renderTaskDetail = function(taskId, campaignId = ''){
      try{
        if(!(typeof isCurrentUserAdmin === 'function' && isCurrentUserAdmin())){
          const visible = typeof getVisibleTasksForCurrentUser === 'function' ? (getVisibleTasksForCurrentUser() || []) : [];
          const exactVisible = visible.find(task => taskIdMatch(task, taskId, campaignId));
          if(exactVisible){
            if(typeof openTaskModal === 'function') return openTaskModal(exactVisible);
          }
        }
      }catch(_){ }
      return prevRenderTaskDetail.apply(this, arguments);
    };
  }

  try{ if(typeof renderTasksPage === 'function') renderTasksPage(); if(typeof renderUserDashboard === 'function') renderUserDashboard(); }catch(_){ }
  console.info(`${VERSION} loaded`);
})();

