    const approvedStep = arr(task?.steps).some(step => step?.adminOnly && step?.done && ident(step?.label || '').includes(ident('اعتماد')));
    return !!(approvedStep || task?.structureApprovedAt || task?.approvedAt || s?.approvedAt || state.includes('approved') || state.includes('distributed') || state.includes(ident('معتمد')));
