      const progress = typeof campaignRequiredProgressFromTasks === 'function' ? campaignRequiredProgressFromTasks(related) : 0;
      const publish = typeof campaignPublishProgress === 'function' ? campaignPublishProgress(campaign) : 0;
      const structureAttached = typeof campaignStructureAttachedCount === 'function' ? campaignStructureAttachedCount(related) : 0;
      const contentWaiting = related.filter(task => taskIsExec(task) && (task.waitingForApproval || task.structureLinkPending || task.deferredDeadlineUntilContentApproval)).length;
      const taskTemplateAttached = related.filter(task => task?.taskTemplate && (task.taskTemplate.fileName || task.taskTemplate.fileData || task.taskTemplate.status === 'uploaded')).length;
